content.text:
The syntax of a `for...of` loop is:
```javascript
for (variable of iterable) {
  // code to execute
}
```
- **Variable**: Represents each element of the iterable in each iteration.
- **Iterable**: An array, string, Set, Map, or other iterable object.
- The loop iterates over each element one by one.

content.code:
// Basic for...of loop example
const fruits = ['apple', 'pear', 'orange'];
for (let fruit of fruits) {
  console.log(fruit);
}
// Output:
// apple
// pear
// orange

// for...of loop with a string
const word = 'Hello';
for (let char of word) {
  console.log(char);
}
// Output:
// H
// e
// l
// l
// o

// break and continue example
const numbers = [1, 2, 3, 4, 5];
for (let num of numbers) {
  if (num === 3) {
    break; // stops the loop
  }
  console.log(num);
}
// Output:
// 1
// 2

for (let num of numbers) {
  if (num === 3) {
    continue; // skips 3
  }
  console.log(num);
}
// Output:
// 1
// 2
// 4
// 5

// for...of loop with Set
const uniqueNumbers = new Set([1, 2, 2, 3, 4]);
for (let num of uniqueNumbers) {
  console.log(num);
}
// Output:
// 1
// 2
// 3
// 4

// for...of loop with Map
const person = new Map([
  ['name', 'Aygun'],
  ['age', 30],
  ['job', 'Teacher']
]);
for (let [key, value] of person) {
  console.log(`Key: ${key}, Value: ${value}`);
}
// Output:
// Key: name, Value: Aygun
// Key: age, Value: 30
// Key: job, Value: Teacher

// Error-prone example
// Error: Non-iterable object
const person = { name: 'Samad', age: 22 };
// for (let value of person) {
//   console.log(value); // Error: person is not iterable
// }
// Correct approach (using Object.values)
const values = Object.values(person);
for (let value of values) {
  console.log(value);
}
// Output:
// Samad
// 22

